import numpy as np
from PIL import Image
strength = params.get('strength', 1.0)
arr = np.array(img.convert('RGB'))
h, w = arr.shape[:2]
cx, cy = w/2, h/2
map_x = np.zeros((h, w), dtype=np.float32)
map_y = np.zeros((h, w), dtype=np.float32)
for y in range(h):
    for x in range(w):
        dx, dy = (x - cx) / cx, (y - cy) / cy
        r = np.sqrt(dx*dx + dy*dy)
        if r > 0 and r < 1:
            z = np.sqrt(1 - r*r) * strength
            factor = 1 / (1 + z)
        else:
            factor = 1
        map_x[y,x] = cx + dx * cx * factor
        map_y[y,x] = cy + dy * cy * factor
try:
    import cv2
    result = cv2.remap(arr, map_x.astype(np.float32), map_y.astype(np.float32), cv2.INTER_LINEAR)
    return Image.fromarray(result)
except:
    return img.convert('RGB')

import numpy as np
from PIL import Image
intensity = params.get('intensity', 0.5)
streaks = params.get('streaks', 3)
length = params.get('length', 50)
arr = np.array(img.convert('RGB'), dtype=np.float32)
h, w = arr.shape[:2]
# Détection des sources lumineuses
bright = np.max(arr, axis=2)
bright_mask = bright > 200
# Streaks horizontaux
for y in range(h):
    for x in range(w):
        if bright_mask[y,x]:
            for s in range(1, streaks + 1):
                for dx in range(1, min(w-x, length*s)):
                    fx = x + dx
                    falloff = intensity * (1 - dx/(length*s)) / s
                    if falloff > 0.01:
                        arr[y, fx] = np.clip(arr[y, fx] + arr[y,x] * falloff * 0.3, 0, 255)
return Image.fromarray(arr.astype(np.uint8))
